26	//     Single-case runner — no charge/quench. List cases or run one.
27	
28	// RCG output discipline: all emission via rbtdrg_*! — no direct println!/eprintln!
29	
30	#![allow(non_camel_case_types)]
31	#![allow(private_interfaces)]
32	#![deny(warnings)]
33	
34	use std::path::PathBuf;
35	use std::process::ExitCode;
36	
37	use rbtd::rbtdrc_crucible::{
38	    rbtdrc_lookup_fixture, rbtdrc_lookup_suite, rbtdrc_set_context, rbtdrc_take_context,
39	    RBTDRC_FIXTURES, RBTDRC_SUITES,
40	};
41	use rbtd::rbtdre_engine::{
42	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
43	    rbtdre_run_fixture, rbtdre_run_single_case, rbtdre_tree_clean,
44	};
45	use rbtd::rbtdri_invocation::{
46	    rbtdri_Context, rbtdri_invoke_global,
47	    RBTDRI_BURD_TEMP_DIR_KEY,
48	};
49	use rbtd::rbtdgc_consts::RBTDGC_CRUCIBLE_ACTIVE;
50	use rbtd::rbtdrx_platform::rbtdrx_path_from_env;
51	
52	fn main() -> ExitCode {
53	    let args: Vec<String> = std::env::args().collect();
54	
55	    match args.get(1).map(|s| s.as_str()) {
56	        Some("single") => rbtdb_run_single(&args[2..]),
57	        Some("suite") => rbtdb_run_suite(&args[2..]),
58	        _ => rbtdb_run_fixture(&args[1..]),
59	    }
60	}
61	
62	struct rbtdb_Roots {
63	    trace_root: PathBuf,
64	    burv_temp_root: PathBuf,
65	    burv_output_root: PathBuf,
66	}
67	
68	fn rbtdb_allocate_roots() -> Result<rbtdb_Roots, String> {
69	    let burd_temp = rbtdrx_path_from_env(RBTDRI_BURD_TEMP_DIR_KEY)?;
70	
71	    // Both BURV roots are anchored under the per-run trace dir
72	    // (BURD_TEMP_DIR/rbtd), which is stable for the life of the run. The output
73	    // root deliberately does NOT live under BURD_OUTPUT_DIR (output-buk/current):
74	    // that dir is cleared at the start of every BUK dispatch, so a fact captured
75	    // there can be deleted out from under a still-running invocation by any
76	    // default-root dispatch — leaving the durable temp copy as the only survivor
77	    // (the failure that made rbgp_fact_governor_sa_email unreadable mid-suite).
78	    let trace_root = burd_temp.join("rbtd");
79	    let burv_temp_root = trace_root.join("burv-temp");
80	    let burv_output_root = trace_root.join("burv-output");
81	
82	    std::fs::create_dir_all(&trace_root)
83	        .map_err(|e| format!("rbtd: failed to create trace root '{}': {}", trace_root.display(), e))?;
84	    std::fs::create_dir_all(&burv_temp_root)
85	        .map_err(|e| format!("rbtd: failed to create burv temp root '{}': {}", burv_temp_root.display(), e))?;
86	    std::fs::create_dir_all(&burv_output_root)
87	        .map_err(|e| format!("rbtd: failed to create burv output root '{}': {}", burv_output_root.display(), e))?;
88	
89	    Ok(rbtdb_Roots { trace_root, burv_temp_root, burv_output_root })
90	}
91	
92	// ── Single-fixture runner ────────────────────────────────────
93	
94	fn rbtdb_run_fixture(args: &[String]) -> ExitCode {
95	    let fixture = match args.first() {
96	        Some(n) => n,
97	        None => rbtd::rbtdrg_fatal_now!(
98	            "rbtd: usage: rbtd <fixture>\n\
99	             theurge must be launched via tabtarget (e.g. tt/rbw-tf.FixtureRun.sh tadmor)"
100	        ),
101	    };
102	
103	    let project_root = match std::env::current_dir() {
104	        Ok(p) => p,
105	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
106	    };
107	
108	    // Run-start hygiene guard (suite only). A suite run commits a sequence of
109	    // hallmark/yoke changes; starting on a dirty tree would interleave the
110	    // operator's uncommitted edits with those commits. Single-case mode is the
111	    // crucible-debug loop and is intentionally left unguarded.
112	    if let Err(msg) = rbtdre_tree_clean(&project_root) {
113	        rbtd::rbtdrg_fatal_now!(
114	            "rbtd: refusing to start a suite run on a dirty working tree — \
115	             commit or stash first.\n{}",
116	            msg
117	        );
118	    }
119	
120	    let roots = match rbtdb_allocate_roots() {
121	        Ok(r) => r,
122	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
123	    };
124	
125	    let ctx = rbtdri_Context::new(
126	        &project_root,
127	        fixture,
128	        &roots.burv_temp_root,
129	        &roots.burv_output_root,
130	    );
131	
132	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
133	        Some(f) => f,
134	        None => rbtd::rbtdrg_fatal_now!(
135	            "rbtd: fixture '{}' has no registered Fixture — \
136	             no Fixture static is bound. \
137	             Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
138	            fixture
139	        ),
140	    };
141	
142	    rbtdrc_set_context(ctx);
143	
144	    let colors = rbtdre_detect_colors();
145	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &roots.trace_root);
146	
147	    let _ctx = rbtdrc_take_context();
148	
149	    let result = match run_result {
150	        Ok(r) => r,
151	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: {}", msg),
152	    };
153	
154	    rbtdre_print_summary(&result, &colors);
155	
156	    if result.failed > 0 {
157	        rbtd::rbtdrg_error_now!("rbtd: {} case(s) failed", result.failed);
158	        ExitCode::FAILURE
159	    } else {
160	        ExitCode::SUCCESS
161	    }
162	}
163	
164	// ── Suite runner ─────────────────────────────────────────────
165	
166	fn rbtdb_run_suite(args: &[String]) -> ExitCode {
167	    let suite = match args.first() {
168	        Some(name) => match rbtdrc_lookup_suite(name) {
169	            Some(s) => s,
170	            None => {
171	                rbtd::rbtdrg_error_now!("rbtd suite: unknown suite '{}'", name);
172	                rbtdb_list_suites();
173	                return ExitCode::FAILURE;
174	            }
175	        },
176	        None => {
177	            rbtd::rbtdrg_error_now!("rbtd suite: no suite argument");
178	            rbtdb_list_suites();
179	            return ExitCode::FAILURE;
180	        }
181	    };
182	
183	    let project_root = match std::env::current_dir() {
184	        Ok(p) => p,
185	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
186	    };
187	
188	    // Run-start hygiene guard, once per suite (under the bash loop it ran once
189	    // per fixture). A suite commits a sequence of hallmark/yoke changes; a dirty
190	    // tree at the start would interleave the operator's uncommitted edits.
191	    if let Err(msg) = rbtdre_tree_clean(&project_root) {
192	        rbtd::rbtdrg_fatal_now!(
193	            "rbtd: refusing to start a suite run on a dirty working tree — \
194	             commit or stash first.\n{}",
195	            msg
196	        );
197	    }
198	
199	    // Roots allocated once per suite; all fixtures share the trace/burv roots.
200	    // This matches the bash loop, where every per-fixture process inherited the
201	    // same BURD_TEMP_DIR and thus the same trace root.
202	    let roots = match rbtdb_allocate_roots() {
203	        Ok(r) => r,
204	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
205	    };
206	
207	    let colors = rbtdre_detect_colors();
208	
209	    let mut total_passed = 0usize;
210	    let mut total_failed = 0usize;
211	    let mut total_skipped = 0usize;
212	    let mut ran = 0usize;
213	
214	    // Sequential, fail-fast across fixtures — matches the bash for-loop under
215	    // `set -e`. A fixture whose cases fail (or whose setup errors) stops the
216	    // suite; fixtures already run have charged-and-quenched cleanly.
217	    //
218	    // Note: a case that *panics* (rather than returning a Fail verdict) unwinds
219	    // past its fixture's quench and aborts the whole suite process with that
220	    // fixture's crucible left charged — the same leak the per-process bash loop
221	    // had. Routine failure is always a Fail verdict, which quenches normally
222	    // (teardown is finally-shaped in rbtdre_run_fixture).
223	    let mut next_invoke_count = 0u32;
224	    for fixture in suite.fixtures {
225	        let mut ctx = rbtdri_Context::new(
226	            &project_root,
227	            fixture.name,
228	            &roots.burv_temp_root,
229	            &roots.burv_output_root,
230	        );
231	        // Carry the BURV invoke counter across fixtures so per-invoke dir names
232	        // never collide between fixtures. A fresh Context starts at 0, so without
233	        // this every fixture's first invoke reuses invoke-00000 — and bud's
234	        // start-of-dispatch current/->previous/ promotion then leaks the prior
235	        // fixture's chaining facts into a non-chained invoke's previous/.
236	        // Suite-monotonic numbering gives each invoke its own dir, closing that.
237	        ctx.set_invoke_count(next_invoke_count);
238	        rbtdrc_set_context(ctx);
239	
240	        let run_result = rbtdre_run_fixture(fixture, &colors, &roots.trace_root);
241	
242	        next_invoke_count = rbtdrc_take_context().invoke_count();
243	
244	        match run_result {
245	            Ok(result) => {
246	                rbtdre_print_summary(&result, &colors);
247	                total_passed += result.passed;
248	                total_failed += result.failed;
249	                total_skipped += result.skipped;
250	                ran += 1;
251	                if result.failed > 0 {
252	                    break;
253	                }
254	            }
255	            Err(msg) => {
256	                rbtd::rbtdrg_error_now!("rbtd: fixture '{}': {}", fixture.name, msg);
257	                total_failed += 1;
258	                ran += 1;
259	                break;
260	            }
261	        }
262	    }
263	
264	    rbtd::rbtdrg_info_now!(
265	        "Suite '{}': {} fixture(s) run, {} passed, {} failed, {} skipped",
266	        suite.name, ran, total_passed, total_failed, total_skipped
267	    );
268	
269	    if total_failed > 0 {
270	        ExitCode::FAILURE
271	    } else {
272	        ExitCode::SUCCESS
273	    }
274	}
275	
276	fn rbtdb_list_suites() {
277	    rbtd::rbtdrg_info_now!("available suites:");
278	    for s in RBTDRC_SUITES {
279	        rbtd::rbtdrg_info_now!("  {}", s.name);
280	    }
281	}
282	
283	// ── Single-case runner ───────────────────────────────────────
284	
285	fn rbtdb_run_single(args: &[String]) -> ExitCode {
286	    let fixture = match args.first() {
287	        Some(f) => f,
288	        None => {
289	            rbtd::rbtdrg_error_now!(
290	                "rbtd single: usage: rbtd single <fixture> [case]\n\
291	                 omit case to list all cases for the fixture"
292	            );
293	            rbtdb_list_fixtures();
294	            return ExitCode::FAILURE;
295	        }
296	    };
297	
298	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
299	        rbtd::rbtdrg_error_now!("rbtd single: unknown fixture '{}'", fixture);
300	        rbtdb_list_fixtures();
301	        return ExitCode::FAILURE;
302	    }
303	
304	    // Set up execution context early — needed for charge check and case execution
305	    let project_root = match std::env::current_dir() {
306	        Ok(p) => p,
307	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
308	    };
309	
310	    let roots = match rbtdb_allocate_roots() {
311	        Ok(r) => r,
312	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
313	    };
314	
315	    // Context is required for every case execution path (rbtdrc_with_ctx).
316	    // Fixtures with a setup hook (crucible charge) additionally verify their
317	    // crucible is charged externally — single-case mode never charges.
318	    let mut ctx = rbtdri_Context::new(
319	        &project_root,
320	        fixture,
321	        &roots.burv_temp_root,
322	        &roots.burv_output_root,
323	    );
324	
325	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
326	        Some(f) => f,
327	        None => rbtd::rbtdrg_fatal_now!(
328	            "rbtd single: fixture '{}' has no registered Fixture",
329	            fixture
330	        ),
331	    };
332	
333	    if fixture_def.setup.is_some() {
334	        match rbtdri_invoke_global(
335	            &mut ctx,
336	            RBTDGC_CRUCIBLE_ACTIVE,
337	            &[fixture],
338	            &[],
339	        ) {
340	            Ok(r) if r.exit_code == 0 => {}
341	            _ => rbtd::rbtdrg_fatal_now!(
342	                "rbtd single: crucible not charged for '{}'\n\
343	                 charge first: tt/rbw-cC.Charge.{}.sh",
344	                fixture, fixture
345	            ),
346	        }
347	    }
348	
349	    rbtdrc_set_context(ctx);
350	
351	    let cases = fixture_def.cases;
352	
353	    // No case argument — list all cases
354	    let case_name = match args.get(1) {
355	        None => {
356	            rbtdre_list_cases(cases);
357	            return ExitCode::SUCCESS;
358	        }
359	        Some(n) => n,
360	    };
361	
362	    // Find the case
363	    let case = match rbtdre_find_case(cases, case_name) {
364	        Some(c) => c,
365	        None => {
366	            rbtd::rbtdrg_error_now!(
367	                "rbtd single: case '{}' not found in fixture '{}'",
368	                case_name, fixture
369	            );
370	            rbtdre_list_cases(cases);
371	            return ExitCode::FAILURE;
372	        }
373	    };
374	
375	    let colors = rbtdre_detect_colors();
376	    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
377	        Ok(r) => r,
378	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: case execution error: {}", msg),
379	    };
380	
381	    rbtdre_print_summary(&result, &colors);
382	
383	    if result.failed > 0 {
384	        ExitCode::FAILURE
385	    } else {
386	        ExitCode::SUCCESS
387	    }
388	}
389	
390	fn rbtdb_list_fixtures() {
391	    rbtd::rbtdrg_info_now!("available fixtures:");
392	    for f in RBTDRC_FIXTURES {
393	        rbtd::rbtdrg_info_now!("  {}", f.name);
394	    }
395	}
